"use strict";(self.webpackChunkelite_website=self.webpackChunkelite_website||[]).push([[8469],{63546:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>m,frontMatter:()=>s,metadata:()=>u,toc:()=>l});var i=n(85893),a=n(11151),o=n(92035);n(82566);const s={authors:["calo"],tags:["journal","paper","IoT","human-computer interaction"],description:'We announce the publication the paper "Enhancing smart home interaction through multimodal command disambiguation" in Personal and Ubiquitous Computing, a leading journal in the field of ubiquitous and pervasive computing.',image:"./background.jpg",image_alt:"Intro slide of the paper presentation"},r="Study on Enhancing Smart Home Interactions Published in Personal and Ubiquitous Computing",u={permalink:"/news/2024/07/25/puc-multimodal-disambiguation",source:"@site/news/2024-07-25-puc-multimodal-disambiguation/index.mdx",title:"Study on Enhancing Smart Home Interactions Published in Personal and Ubiquitous Computing",description:'We announce the publication the paper "Enhancing smart home interaction through multimodal command disambiguation" in Personal and Ubiquitous Computing, a leading journal in the field of ubiquitous and pervasive computing.',date:"2024-07-25T00:00:00.000Z",tags:[{inline:!0,label:"journal",permalink:"/news/tags/journal"},{inline:!0,label:"paper",permalink:"/news/tags/paper"},{inline:!0,label:"IoT",permalink:"/news/tags/io-t"},{inline:!0,label:"human-computer interaction",permalink:"/news/tags/human-computer-interaction"}],readingTime:2.875,hasTruncateMarker:!0,authors:[{name:"Tommaso Cal\xf2",title:"Ph.D. Student",url:"https://tommasocalo.github.io",imageURL:"/img/people/TommasoCalo.jpeg",key:"calo"}],frontMatter:{authors:["calo"],tags:["journal","paper","IoT","human-computer interaction"],description:'We announce the publication the paper "Enhancing smart home interaction through multimodal command disambiguation" in Personal and Ubiquitous Computing, a leading journal in the field of ubiquitous and pervasive computing.',image:"./background.jpg",image_alt:"Intro slide of the paper presentation"},unlisted:!1,nextItem:{title:"2nd AccessCoVE Project Meeting",permalink:"/news/2024/07/15/AccessCoVE-Meeting"}},c={image:n(48905).Z,authorsImageUrls:[void 0]},l=[];function d(e){const t={a:"a",hr:"hr",li:"li",p:"p",strong:"strong",ul:"ul",...(0,a.a)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsxs)(t.p,{children:["We are excited to announce the publication of our latest research paper in Personal and Ubiquitous Computing. The study, titled ",(0,i.jsx)(t.strong,{children:'"Enhancing smart home interaction through multimodal command disambiguation,"'})," and conducted by me and ",(0,i.jsx)(t.strong,{children:"Luigi De Russis"}),", explores an innovative approach to making smart homes more intuitive and responsive to user commands."]}),"\n",(0,i.jsxs)(t.p,{children:['Imagine a scenario where a user says, "Set a cozy mood in the living room." This simple command can be interpreted in various ways. Does "cozy" mean dimming the lights, adjusting the temperature, or perhaps playing soft background music?\nWe propose a novel ',(0,i.jsx)(t.strong,{children:"multimodal disambiguation approach"}),' that integrates visual and textual cues with natural language commands. We leverage large language models (LLMs) to detect when a user\'s command is unclear and generate appropriate clarification options. These options are presented to users through either visual representations or textual descriptions, depending on the context and nature of the ambiguity. For instance, if the user asks to "set a relaxing atmosphere," the system might offer visual representations of different room settings, as the concept of "relaxing" is often better conveyed through images. On the other hand, for a command like "adjust the temperature for optimal sleep," the system could provide textual options detailing specific temperature ranges and their benefits for sleep. This adaptive approach ensures that users can clarify their intentions in the most intuitive and efficient manner, enhancing the overall smart home experience.']}),"\n",(0,i.jsx)("p",{className:"text--center",children:(0,i.jsx)("img",{src:o.Z,alt:"Diagram showing the smart home interaction system. Components include User, Concept Disambiguation, Context Advisor, Context and Concept Stores, with LLMs processing requests and generating text/image responses."})}),"\n",(0,i.jsx)(t.p,{children:"Our method, as illustrated in the image, consists of several interconnected components. The Context Advisor, powered by a Large Language Model (LLM), extracts and saves context information from user requests in the Context Store. This stored context is then used by the Concept Disambiguation component, also driven by an LLM, to interpret and clarify ambiguous user commands. The disambiguation process results in either textual or visual representations presented to the user. Once the user selects their preferred interpretation, this concept is saved in the Concept Store. This stored information is then used to enrich the context for future interactions, creating a feedback loop that continually improves the system's understanding of user preferences and intentions. This cyclical process allows our system to adapt and provide increasingly accurate and personalized responses over time."}),"\n",(0,i.jsxs)(t.p,{children:["The effectiveness of the approach was evaluated through a comprehensive ",(0,i.jsx)(t.strong,{children:"user study involving 13 participants"}),". This study provided valuable insights into how users interact with the system and their preferences for different types of disambiguation. Users generally found the multimodal disambiguation approach helpful in clarifying their intentions and achieving their desired outcomes in the smart home environment.\nInterestingly, our results showed that textual descriptions were slightly more effective than visual cues for clarification. However, this preference was not universal, and we found that ",(0,i.jsx)(t.strong,{children:"both modalities had their strengths in different contexts"}),"."]}),"\n",(0,i.jsxs)(t.p,{children:["This work aligns with our broader goal of making technology more accessible and user-friendly, adapting to human communication patterns rather than requiring users to adapt to rigid system commands.\nThe full paper findings, and implications for future research, is ",(0,i.jsx)(t.a,{href:"https://doi.org/10.1007/s00779-024-01827-3",children:"now available in the latest issue of Personal and Ubiquitous Computing"}),". We encourage those interested in smart home technology, human-computer interaction, or the application of language models in practical settings to read the complete study."]}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.p,{children:"Additional information:"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:(0,i.jsx)(t.a,{href:"https://iris.polito.it/handle/11583/2990415",children:"Paper on PORTO@IRIS"})}),"\n"]})]})}function m(e={}){const{wrapper:t}={...(0,a.a)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},48905:(e,t,n)=>{n.d(t,{Z:()=>i});const i=n.p+"assets/images/background-570e63a68c4726390a814cf8d36054ec.jpg"},82566:(e,t,n)=>{n.p},92035:(e,t,n)=>{n.d(t,{Z:()=>i});const i=n.p+"assets/images/method-ae2e133044519e152049a5c1b8fd8c71.png"},11151:(e,t,n)=>{n.d(t,{Z:()=>r,a:()=>s});var i=n(67294);const a={},o=i.createContext(a);function s(e){const t=i.useContext(o);return i.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(o.Provider,{value:t},e.children)}}}]);